const State = enum(u8) {
    idle,
    one_e,
    circumflex,
    literal,
};

const ProcessKeyEventResult = extern struct {
    num_backspaces: u8,
    num_chars: u8,
    swallow_event: bool,
    chars: [*]const u16,
};

// --- Internal variables ---

var state: State = .idle;
var first_e_upper: bool = false;
var gap: u8 = 0;
var bufs: [2][2]u16 = .{ .{ 0, 0 }, .{ 0, 0 } };
var active: u1 = 0;

const passthrough: ProcessKeyEventResult = .{
    .num_backspaces = 0,
    .num_chars = 0,
    .swallow_event = false,
    .chars = @ptrCast(&bufs[0]),
};

// --- Internal functions ---

fn emit(num_backspaces: u8, chars: []const u16) ProcessKeyEventResult {
    const buf = @as([*]u16, @ptrCast(&bufs[active]));
    for (chars, 0..) |c, i| buf[i] = c;
    active ^= 1;
    return .{
        .num_backspaces = num_backspaces,
        .num_chars = @intCast(chars.len),
        .swallow_event = true,
        .chars = buf,
    };
}

fn is_e(c: u16) bool {
    return c == 'e' or c == 'E';
}

fn is_alphanumeric(c: u16) bool {
    return (c >= '0' and c <= '9') or
        (c >= 'A' and c <= 'Z') or
        (c >= 'a' and c <= 'z');
}

fn handle_e(char_code: u16) ProcessKeyEventResult {
    const upper = char_code == 'E';
    switch (state) {
        .idle => {
            state = .one_e;
            first_e_upper = upper;
            return passthrough;
        },
        .one_e => {
            state = .circumflex;
            const c: u16 = if (first_e_upper) 0x00CA else 0x00EA;
            return emit(1, &.{c});
        },
        .circumflex => {
            state = .literal;
            const c0: u16 = if (first_e_upper) 'E' else 'e';
            const c1: u16 = if (upper) 'E' else 'e';
            return emit(1, &.{ c0, c1 });
        },
        .literal => unreachable,
    }
}

// --- Public functions ---

export fn reset_state() void {
    state = .idle;
    first_e_upper = false;
    gap = 0;
}

export fn process_backspace() ProcessKeyEventResult {
    if (gap > 0) {
        gap -= 1;
    } else switch (state) {
        .literal => state = .one_e,
        .idle => {},
        else => reset_state(),
    }
    return passthrough;
}

export fn process_key_event(char_code: u16) ProcessKeyEventResult {
    if (is_e(char_code)) {
        if (gap == 0 and state != .literal) return handle_e(char_code);
    } else if (!is_alphanumeric(char_code)) {
        reset_state();
        return passthrough;
    } else if (state == .idle) {
        return passthrough;
    }

    if (gap == 255) {
        reset_state();
        return passthrough;
    }
    gap += 1;
    return passthrough;
}

#ifndef LIBLEX_H
#define LIBLEX_H

#include <stdint.h>
#include <stdbool.h>

typedef struct {
    uint8_t num_backspaces;
    uint8_t num_chars;
    bool swallow_event;
    const uint16_t *chars;
} ProcessKeyEventResult;

ProcessKeyEventResult process_key_event(uint16_t char_code);
ProcessKeyEventResult process_backspace(void);
void reset_state(void);

#endif

import Cocoa

private let syntheticTag: Int64 = 0x4C4558

class AppDelegate: NSObject, NSApplicationDelegate {
    var statusItem: NSStatusItem!
    var eventTap: CFMachPort?
    var syntheticSource: CGEventSource?

    func applicationDidFinishLaunching(_ notification: Notification) {
        syntheticSource = CGEventSource(stateID: .privateState)
        syntheticSource?.userData = syntheticTag
        setupMenuBar()
        requestAccessAndStartTap()
        observeAppSwitch()
    }

    private func setupMenuBar() {
        statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
        if let button = statusItem.button {
            button.title = "⌨"
        }
        let menu = NSMenu()
        menu.addItem(NSMenuItem(title: "Exit", action: #selector(NSApplication.terminate(_:)), keyEquivalent: "q"))
        statusItem.menu = menu
    }

    private func requestAccessAndStartTap() {
        let options = [kAXTrustedCheckOptionPrompt.takeUnretainedValue(): true] as CFDictionary
        if !AXIsProcessTrustedWithOptions(options) {
            print("Accessibility permission required. Please grant access in System Settings > Privacy & Security > Accessibility, then relaunch.")
            return
        }
        startEventTap()
    }

    private func observeAppSwitch() {
        NSWorkspace.shared.notificationCenter.addObserver(
            forName: NSWorkspace.didActivateApplicationNotification,
            object: nil,
            queue: .main
        ) { _ in
            reset_state()
        }
    }

    private func startEventTap() {
        let eventMask: CGEventMask = (1 << CGEventType.keyDown.rawValue)
            | (1 << CGEventType.flagsChanged.rawValue)
            | (1 << CGEventType.tapDisabledByTimeout.rawValue)
            | (1 << CGEventType.tapDisabledByUserInput.rawValue)

        let selfPtr = Unmanaged.passUnretained(self).toOpaque()

        guard let tap = CGEvent.tapCreate(
            tap: .cgSessionEventTap,
            place: .headInsertEventTap,
            options: .defaultTap,
            eventsOfInterest: eventMask,
            callback: eventTapCallback,
            userInfo: selfPtr
        ) else {
            print("Failed to create event tap. Ensure Input Monitoring permission is granted.")
            return
        }

        eventTap = tap
        let runLoopSource = CFMachPortCreateRunLoopSource(kCFAllocatorDefault, tap, 0)
        CFRunLoopAddSource(CFRunLoopGetCurrent(), runLoopSource, .commonModes)
        CGEvent.tapEnable(tap: tap, enable: true)
        print("Event tap started.")
    }

    func emitSyntheticEvents(result: ProcessKeyEventResult) {
        guard let source = syntheticSource else { return }

        for _ in 0..<result.num_backspaces {
            if let down = CGEvent(keyboardEventSource: source, virtualKey: 0x33, keyDown: true),
               let up = CGEvent(keyboardEventSource: source, virtualKey: 0x33, keyDown: false) {
                down.post(tap: .cgSessionEventTap)
                up.post(tap: .cgSessionEventTap)
            }
        }

        for i in 0..<Int(result.num_chars) {
            var char = result.chars[i]
            if let down = CGEvent(keyboardEventSource: source, virtualKey: 0, keyDown: true),
               let up = CGEvent(keyboardEventSource: source, virtualKey: 0, keyDown: false) {
                down.keyboardSetUnicodeString(stringLength: 1, unicodeString: &char)
                up.keyboardSetUnicodeString(stringLength: 1, unicodeString: &char)
                down.post(tap: .cgSessionEventTap)
                up.post(tap: .cgSessionEventTap)
            }
        }
    }
}

func eventTapCallback(
    proxy: CGEventTapProxy,
    type eventType: CGEventType,
    event: CGEvent,
    userInfo: UnsafeMutableRawPointer?
) -> Unmanaged<CGEvent>? {
    guard let userInfo = userInfo else {
        return Unmanaged.passUnretained(event)
    }
    let appDelegate = Unmanaged<AppDelegate>.fromOpaque(userInfo).takeUnretainedValue()

    if eventType == .tapDisabledByTimeout || eventType == .tapDisabledByUserInput {
        if let tap = appDelegate.eventTap {
            CGEvent.tapEnable(tap: tap, enable: true)
        }
        reset_state()
        return Unmanaged.passUnretained(event)
    }

    if eventType == .flagsChanged {
        return Unmanaged.passUnretained(event)
    }

    guard eventType == .keyDown else {
        return Unmanaged.passUnretained(event)
    }

    if event.getIntegerValueField(.eventSourceUserData) == syntheticTag {
        return Unmanaged.passUnretained(event)
    }

    let flags = event.flags
    let modifierMask: CGEventFlags = [.maskCommand, .maskControl, .maskAlternate]
    if !flags.intersection(modifierMask).isEmpty {
        reset_state()
        return Unmanaged.passUnretained(event)
    }

    let keyCode = event.getIntegerValueField(.keyboardEventKeycode)
    if keyCode == 0x33 {
        let _ = process_backspace()
        return Unmanaged.passUnretained(event)
    }

    var charCount: Int = 0
    event.keyboardGetUnicodeString(maxStringLength: 0, actualStringLength: &charCount, unicodeString: nil)

    guard charCount == 1 else {
        reset_state()
        return Unmanaged.passUnretained(event)
    }

    var unicodeChar: UniChar = 0
    event.keyboardGetUnicodeString(maxStringLength: 1, actualStringLength: &charCount, unicodeString: &unicodeChar)

    let result = process_key_event(unicodeChar)

    if result.swallow_event {
        appDelegate.emitSyntheticEvents(result: result)
        return nil
    }

    return Unmanaged.passUnretained(event)
}

let app = NSApplication.shared
app.setActivationPolicy(.accessory)

let delegate = AppDelegate()
app.delegate = delegate
app.run()

const std = @import("std");

pub fn build(b: *std.Build) void {
    const optimize = b.standardOptimizeOption(.{});

    // Match LSMinimumSystemVersion in Info.plist
    const target = b.resolveTargetQuery(.{
        .os_version_min = .{ .semver = .{ .major = 26, .minor = 0, .patch = 0 } },
    });

    // Step 1: Build the Zig static library
    const lib = b.addLibrary(.{
        .name = "lex",
        .linkage = .static,
        .root_module = b.createModule(.{
            .root_source_file = b.path("src/liblex.zig"),
            .target = target,
            .optimize = optimize,
        }),
    });

    // Step 2: Re-pack the archive (Zig master workaround for non-8-byte-aligned members)
    const repack = b.addSystemCommand(&.{
        "/bin/sh", "-c",
        \\tmp=$(mktemp -d) && \
        \\cp "$1" "$tmp/lib.a" && \
        \\(cd "$tmp" && ar x lib.a && rm lib.a && chmod 644 *.o && /usr/bin/ar rcs lib.a *.o) && \
        \\cp "$tmp/lib.a" "$1" && \
        \\rm -rf "$tmp"
        ,
        "--",
    });
    repack.addArtifactArg(lib);
    repack.has_side_effects = true;

    // Step 3: Compile Swift and link with the Zig library
    const swiftc = b.addSystemCommand(&.{
        "swiftc",
        "macos/Lex.swift",
        "-import-objc-header",
        "src/liblex.h",
    });
    swiftc.addPrefixedDirectoryArg("-L", lib.getEmittedBinDirectory());
    swiftc.addArgs(&.{"-llex"});
    swiftc.addArgs(&.{ "-o", "macos/Lex.app/Contents/MacOS/Lex" });
    swiftc.step.dependOn(&repack.step);
    swiftc.has_side_effects = true;

    // Step 4: Ad-hoc codesign
    const codesign = b.addSystemCommand(&.{
        "codesign", "-f", "-s", "-", "macos/Lex.app",
    });
    codesign.step.dependOn(&swiftc.step);
    codesign.has_side_effects = true;

    // Wire into default install step
